"""
Stylesheet for the Module 4 lineup dashboard (generated layout).
"""

from __future__ import annotations


def get_dashboard_css() -> str:
    """Return embedded CSS for the dashboard page."""
    return '    body {\n      margin: 0;\n      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Arial, sans-serif;\n      background: #0b1020;\n      color: #e8ecf3;\n    }\n    .wrap {\n      max-width: 1240px;\n      margin: 24px auto;\n      padding: 0 16px;\n      display: grid;\n      grid-template-columns: minmax(300px, 340px) minmax(640px, 1fr);\n      gap: 18px;\n      align-items: start;\n    }\n    .card {\n      background: #141a2f;\n      border: 1px solid #243050;\n      border-radius: 12px;\n      padding: 16px;\n    }\n    h2 {\n      margin-top: 0;\n      font-size: 1.05rem;\n      letter-spacing: 0.02em;\n    }\n    ol {\n      margin: 0;\n      padding-left: 0;\n      list-style: none;\n      display: grid;\n      gap: 8px;\n    }\n    li {\n      background: #1a2340;\n      border: 1px solid #2a3760;\n      border-radius: 8px;\n      padding: 8px 10px;\n    }\n    .slot {\n      display: inline-block;\n      width: 2ch;\n      color: #7ec8ff;\n      font-weight: 600;\n    }\n    .batter-name {\n      font-weight: 500;\n    }\n    .lineup-row {\n      cursor: pointer;\n      transition: border-color 0.15s ease, box-shadow 0.15s ease;\n    }\n    .lineup-row:hover {\n      border-color: #4b6cb0;\n    }\n    .lineup-row.highlighted {\n      border-color: #74b8ff;\n      box-shadow: 0 0 0 2px rgba(116, 184, 255, 0.35);\n    }\n    .lineup-row:focus {\n      outline: 2px solid #74b8ff;\n      outline-offset: 2px;\n    }\n    .role-badge {\n      display: inline-block;\n      margin-left: 8px;\n      padding: 1px 6px;\n      border-radius: 999px;\n      border: 1px solid #3d5892;\n      color: #9ed2ff;\n      background: #192746;\n      font-size: 0.75rem;\n      font-weight: 700;\n      letter-spacing: 0.03em;\n    }\n    .lineup-card {\n      grid-column: 1;\n      grid-row: 1;\n    }\n    .field {\n      grid-column: 2;\n      grid-row: 1;\n      display: flex;\n      flex-direction: column;\n      gap: 12px;\n    }\n    .field-visual {\n      position: relative;\n      min-height: 520px;\n      overflow: hidden;\n      border: 1px solid #2a3760;\n      border-radius: 10px;\n      background:\n        radial-gradient(circle at 50% 72%, #2e6a3f 0%, #225233 45%, #1a3f27 100%);\n    }\n    .diamond {\n      position: absolute;\n      left: 50%;\n      top: 58%;\n      width: 240px;\n      height: 240px;\n      border: 3px solid #d8c39a;\n      transform: translate(-50%, -50%) rotate(45deg);\n      box-sizing: border-box;\n    }\n    .pos {\n      position: absolute;\n      background: rgba(11,16,32,0.85);\n      border: 1px solid #4b5f97;\n      border-radius: 999px;\n      padding: 6px 10px;\n      font-size: 0.82rem;\n      white-space: nowrap;\n      transform: translate(-50%, -50%);\n    }\n    .label {\n      display: inline-block;\n      color: #9ed2ff;\n      font-weight: 700;\n      margin-right: 6px;\n    }\n    .lf { left: 18%; top: 24%; }\n    .cf { left: 50%; top: 16%; }\n    .rf { left: 82%; top: 24%; }\n    .defensive-slot {\n      cursor: grab;\n      user-select: none;\n      padding-right: 34px;\n    }\n    .defensive-slot .player {\n      cursor: pointer;\n      text-decoration: underline dotted rgba(142, 209, 255, 0.45);\n      text-underline-offset: 2px;\n    }\n    .defensive-slot.highlighted {\n      border-color: #74b8ff !important;\n      box-shadow: 0 0 0 2px rgba(116, 184, 255, 0.35);\n    }\n    .defensive-slot.dragging {\n      opacity: 0.72;\n      border-color: #8cc6ff;\n    }\n    .defensive-slot.drop-target {\n      border-color: #74b8ff;\n      box-shadow: 0 0 0 2px rgba(116,184,255,0.25);\n    }\n    .defensive-slot.locked {\n      border-color: #e0b85b;\n      box-shadow: 0 0 0 2px rgba(224,184,91,0.25);\n    }\n    .lock-btn {\n      position: absolute;\n      right: 6px;\n      top: 50%;\n      transform: translateY(-50%);\n      border: 1px solid #4a5f94;\n      border-radius: 999px;\n      background: #1b2846;\n      color: #d8e3ff;\n      font-size: 0.62rem;\n      line-height: 1;\n      padding: 3px 6px;\n      cursor: pointer;\n    }\n    .lock-btn.active {\n      border-color: #e0b85b;\n      background: #5a451e;\n      color: #ffe2a3;\n    }\n    .ss { left: 39%; top: 40%; }\n    .b2 { left: 61%; top: 40%; }\n    .b3 { left: 30%; top: 52%; }\n    .b1 { left: 70%; top: 52%; }\n    .c  { left: 50%; top: 76%; }\n    .dh { left: 79%; top: 76%; }\n    /* Full-width rows below the top row; use auto rows so multiple .module5 blocks stack\n       (Adaptive Planning + Pipeline Connections) instead of sharing grid-row: 2 and overlapping. */\n    .module5 {\n      grid-column: 1 / -1;\n      grid-row: auto;\n    }\n    .field-footer {\n      background: rgba(11,16,32,0.9);\n      border: 1px solid #30416e;\n      border-radius: 10px;\n      padding: 10px 12px;\n      font-size: 0.88rem;\n      line-height: 1.4;\n    }\n    .field-footer .value {\n      color: #8fd1ff;\n      font-weight: 700;\n    }\n    .field-footer .value.conf-high {\n      color: #61d095;\n    }\n    .field-footer .value.conf-medium {\n      color: #f0c45b;\n    }\n    .field-footer .value.conf-low {\n      color: #f17a7a;\n    }\n    .field-footer .hint {\n      color: #bdcae6;\n      margin-top: 4px;\n      font-size: 0.82rem;\n    }\n    .mode-toggle {\n      margin-top: 8px;\n      display: inline-flex;\n      gap: 8px;\n      align-items: center;\n      border: 1px solid #30416e;\n      border-radius: 999px;\n      padding: 4px;\n      background: rgba(11,16,32,0.7);\n    }\n    .mode-toggle button {\n      border: 1px solid #3a4f82;\n      background: #1a2340;\n      color: #c8d6f3;\n      border-radius: 999px;\n      padding: 4px 10px;\n      font-size: 0.78rem;\n      cursor: pointer;\n    }\n    .mode-toggle button.active {\n      background: #24406f;\n      color: #eaf2ff;\n      border-color: #5f93d8;\n      font-weight: 600;\n    }\n    .mode-label {\n      margin-top: 6px;\n      color: #9ed2ff;\n      font-size: 0.8rem;\n    }\n    .predictive-toggle {\n      margin-top: 8px;\n      color: #c7d5f1;\n      font-size: 0.79rem;\n      display: flex;\n      align-items: center;\n      gap: 7px;\n    }\n    .predictive-toggle input {\n      accent-color: #74b8ff;\n    }\n    .field-footer .explain {\n      margin-top: 6px;\n      color: #9ed2ff;\n      font-size: 0.8rem;\n    }\n    .field-footer .subexplain {\n      margin-top: 3px;\n      color: #a8b8db;\n      font-size: 0.76rem;\n    }\n    .field-footer .subexplain.conf-high {\n      color: #86dfae;\n    }\n    .field-footer .subexplain.conf-medium {\n      color: #f2cf73;\n    }\n    .field-footer .subexplain.conf-low {\n      color: #ff9a9a;\n    }\n    .why-panel {\n      margin-top: 10px;\n      border: 1px solid #30416e;\n      border-radius: 10px;\n      background: rgba(9, 14, 30, 0.9);\n      padding: 10px 12px;\n    }\n    .why-panel h4 {\n      margin: 0 0 8px;\n      font-size: 0.86rem;\n      color: #9ed2ff;\n      letter-spacing: 0.02em;\n    }\n    .why-list {\n      margin: 0;\n      padding-left: 0;\n      list-style: none;\n      display: grid;\n      gap: 4px;\n      font-size: 0.8rem;\n      color: #c6d2ef;\n    }\n    .why-list li {\n      border: 1px solid #26355d;\n      border-radius: 7px;\n      background: #151f3b;\n      padding: 6px 8px;\n      line-height: 1.25;\n    }\n    .player-inspector {\n      margin-top: 12px;\n      border: 1px solid #30416e;\n      border-radius: 10px;\n      background: rgba(9, 14, 30, 0.92);\n      padding: 10px 12px;\n    }\n    .player-inspector h4 {\n      margin: 0 0 8px;\n      font-size: 0.86rem;\n      color: #9ed2ff;\n    }\n    .player-inspector .inspector-name {\n      font-weight: 700;\n      color: #eaf2ff;\n      margin-bottom: 6px;\n    }\n    .player-inspector .inspector-grid {\n      display: grid;\n      gap: 4px;\n      font-size: 0.78rem;\n      color: #b8c8e8;\n    }\n    .player-inspector .inspector-pos {\n      color: #8fd1ff;\n      font-weight: 600;\n    }\n    .why-score {\n      color: #8fd1ff;\n      font-weight: 700;\n    }\n    .recommendations {\n      margin: 0 0 12px;\n      padding-left: 0;\n      list-style: none;\n      display: grid;\n      gap: 8px;\n    }\n    .recommendations li {\n      background: #1a2340;\n      border: 1px solid #2a3760;\n      border-radius: 8px;\n      padding: 10px;\n      line-height: 1.35;\n    }\n    .rec-item {\n      cursor: pointer;\n      transition: border-color 0.15s ease, box-shadow 0.15s ease;\n    }\n    .rec-item:hover {\n      border-color: #4b6cb0;\n    }\n    .rec-item.active {\n      border-color: #61d095;\n      box-shadow: 0 0 0 2px rgba(97, 208, 149, 0.28);\n    }\n    .rec-item:focus {\n      outline: 2px solid #61d095;\n      outline-offset: 2px;\n    }\n    tbody tr.inning-row {\n      cursor: pointer;\n      transition: background 0.12s ease;\n    }\n    tbody tr.inning-row:hover {\n      background: #1e2a4d;\n    }\n    tbody tr.inning-row:focus {\n      outline: 2px solid #74b8ff;\n      outline-offset: -2px;\n    }\n    .gs-form {\n      margin-bottom: 16px;\n      padding-bottom: 14px;\n      border-bottom: 1px solid #2a3760;\n    }\n    .gs-form h3 {\n      margin-top: 0;\n      font-size: 0.95rem;\n      color: #bcd3ff;\n    }\n    .gs-hint code {\n      font-size: 0.72rem;\n      color: #9ed2ff;\n    }\n    .gs-grid {\n      display: grid;\n      grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));\n      gap: 10px 14px;\n      align-items: end;\n      margin-top: 10px;\n    }\n    .gs-grid label {\n      display: flex;\n      flex-direction: column;\n      gap: 4px;\n      font-size: 0.78rem;\n      color: #b8c8e8;\n    }\n    .gs-grid input[type="number"],\n    .gs-grid select {\n      padding: 6px 8px;\n      border-radius: 8px;\n      border: 1px solid #3a4f82;\n      background: #121a32;\n      color: #e8ecf3;\n      font-size: 0.85rem;\n    }\n    .gs-bases {\n      display: flex;\n      flex-wrap: wrap;\n      align-items: center;\n      gap: 8px 12px;\n      font-size: 0.78rem;\n      color: #b8c8e8;\n    }\n    .gs-bases-label {\n      font-weight: 600;\n      color: #9ed2ff;\n      margin-right: 4px;\n    }\n    .gs-actions {\n      margin-top: 12px;\n      display: flex;\n      flex-wrap: wrap;\n      align-items: center;\n      gap: 12px 16px;\n    }\n    .gs-btn {\n      border: 1px solid #5f93d8;\n      background: #24406f;\n      color: #eaf2ff;\n      border-radius: 999px;\n      padding: 8px 16px;\n      font-size: 0.82rem;\n      font-weight: 600;\n      cursor: pointer;\n    }\n    .gs-btn:hover {\n      background: #2d4f85;\n    }\n    .gs-auto {\n      font-size: 0.78rem;\n      color: #c7d5f1;\n      display: flex;\n      align-items: center;\n      gap: 6px;\n      cursor: pointer;\n    }\n    #m5-replan-status {\n      margin-top: 8px;\n      margin-bottom: 0;\n    }\n    .recommendations span {\n      color: #c9d4ee;\n      font-size: 0.9rem;\n    }\n    h3 {\n      margin: 0 0 8px;\n      font-size: 0.95rem;\n      color: #bcd3ff;\n    }\n    table {\n      width: 100%;\n      border-collapse: collapse;\n      font-size: 0.9rem;\n    }\n    th, td {\n      border: 1px solid #2a3760;\n      padding: 7px 9px;\n      text-align: left;\n    }\n    th {\n      background: #1b2545;\n      color: #9ed2ff;\n      font-weight: 600;\n    }\n    @media (max-width: 1040px) {\n      .wrap { grid-template-columns: 1fr; }\n      .lineup-card,\n      .field,\n      .module5 {\n        grid-column: 1;\n        grid-row: auto;\n      }\n      .field-visual { min-height: 440px; }\n    }'
